    val depthMap = nums.map { computePopcountDepth(it) }.toTypedArray()

    // For efficient range queries, we use a segment tree
    // Since k can only be up to 5, we can use a 2D array for each k
    val segmentTree = arrayOfNulls<IntArray>(6)
    for (k in 0..5) {
        segmentTree[k] = IntArray(nums.size) { 0 }
        for (i in 0 until nums.size) {
            if (depthMap[i] == k.toLong()) {
                segmentTree[k][i] = 1
            }
        }
    }

    // Build segment trees for each k
    val trees = Array(6) { buildSegmentTree(segmentTree[it], 0, nums.size - 1) }

    // Process queries
    val answer = Array(queries.size) { 0L }
    var idx = 0

    for (query in queries) {
        when (query[0].toInt()) {
            1 -> {
                val l = query[1].toInt()
                val r = query[2].toInt()
                val k = query[3].toInt()
                answer[idx++] = queryRange(trees[k], l, r)
            }
            2 -> {
                val idxUpdate = query[1].toInt()
                val valUpdate = query[2].toInt()
                // Update the value in nums
                nums[idxUpdate] = valUpdate.toLong()
                // Recompute the depth and update the segment trees
                val oldDepth = depthMap[idxUpdate]
                val newDepth = computePopcountDepth(valUpdate.toLong())
                for (k in 0..5) {
                    if (oldDepth == k.toLong()) {
                        trees[k][idxUpdate] = 0
                    }
                    if (newDepth == k.toLong()) {
                        trees[k][idxUpdate] = 1
                    }
                }
                depthMap[idxUpdate] = newDepth
            }
        }
    }

    return answer
}

