fun buildSegmentTree(arr: IntArray, start: Int, end: Int): IntArray {
    val size = 1
    val n = end - start + 1
    val treeSize = 2 * (1 shl (n.let { if (it == 0) 1 else it.ceilLog2().toInt()) }))
    val tree = IntArray(treeSize)

    // Fill leaves
    for (i in start..end) {
        tree[treeSize + i - start] = arr[i]
    }

    // Build the tree
    for (i in treeSize - 1 downTo 1) {
        tree[i] = tree[2 * i] + tree[2 * i + 1]
    }

    return tree
}

fun queryRange(tree: IntArray, l: Int, r: Int): Long {
    return queryRangeHelper(tree, 1, 0, tree.size - 1, l, r)
}

fun queryRangeHelper(tree: IntArray, node: Int, nodeStart: Int, nodeEnd: Int, l: Int, r: Int): Long {
    if (nodeEnd < l || nodeStart > r) {
        return 0
    }
    if (l <= nodeStart && nodeEnd <= r) {
        return tree[node].toLong()
    }
    val mid = (nodeStart + nodeEnd) / 2
    return queryRangeHelper(tree, 2 * node, nodeStart, mid, l, r) + queryRangeHelper(tree, 2 * node + 1, mid + 1, nodeEnd, l, r)
}
